import React, { useEffect, useState } from "react";
import { getAllProjects } from "../../api/api";

const ManageProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await getAllProjects();
      setProjects(res.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  return (
    <div className="flex-1 flex flex-col bg-gray-100 min-h-screen">

      {/* Top Header Bar */}
      <div className="bg-white border-b px-8 py-4 shadow-sm">
        <h2 className="text-lg font-semibold text-gray-700">Projects</h2>
      </div>

      {/* Page Content */}
      <div className="flex-1 p-8">
        <div className="max-w-6xl mx-auto">

          <h1 className="text-3xl font-bold text-gray-800 mb-8">All Projects</h1>

          {loading ? (
            <div className="text-center py-10">
              <div className="w-10 h-10 border-4 border-teal-500 border-t-transparent rounded-full animate-spin mx-auto mb-3"></div>
              <p className="text-gray-500">Loading projects...</p>
            </div>
          ) : projects.length === 0 ? (
            <div className="bg-white p-10 rounded-xl shadow text-center">
              <p className="text-4xl mb-4">📭</p>
              <p className="text-gray-500 text-lg">No projects available</p>
            </div>
          ) : (
            <div className="space-y-4">
              {projects.map((project) => (
                <div
                  key={project.id}
                  className="bg-white border border-gray-200 rounded-xl shadow-sm p-6 hover:shadow-md transition"
                >
                  {/* Header */}
                  <div className="flex justify-between items-center mb-2">
                    <h2 className="text-xl font-semibold text-gray-800">
                      {project.title}
                    </h2>
                    <span
                      className={`px-3 py-1 rounded-full text-xs font-semibold capitalize ${
                        project.status === "completed"
                          ? "bg-blue-100 text-blue-600"
                          : project.status === "in-progress"
                          ? "bg-yellow-100 text-yellow-600"
                          : "bg-green-100 text-green-600"
                      }`}
                    >
                      {project.status || "open"}
                    </span>
                  </div>

                  <p className="text-gray-600 mb-4">{project.description}</p>

                  <hr className="mb-4" />

                  {/* Footer Info */}
                  <div className="flex flex-wrap justify-between text-sm text-gray-500 gap-4">
                    <span>💰 ₹{project.budget?.toLocaleString("en-IN")}</span>
                    <span>📅 {project.deadline ? project.deadline.slice(0, 10) : project.created_at?.slice(0, 10)}</span>
                    <span>👤 {project.client_name || "Client"}</span>
                    <span>🔧 {project.skills || "—"}</span>
                    <span className="text-teal-600 font-medium">
                      {project.proposalsCount || 0} proposals
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default ManageProjects;
